import{_ as a,o as e,c as s,ai as l}from"./chunks/framework.BIXs0jTs.js";const i="/assets/preface-cover.Balx8Fq4.png",u=JSON.parse('{"title":"Claude Code 模式体系","description":"","frontmatter":{"title":"Claude Code 模式体系"},"headers":[],"relativePath":"10-claude-code/modes.md","filePath":"10-claude-code/modes.md","lastUpdated":null}'),n={name:"10-claude-code/modes.md"};function o(r,t,d,g,h,p){return e(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="第-2-章-claude-code-的模式体系" tabindex="-1">第 2 章　Claude Code 的模式体系 <a class="header-anchor" href="#第-2-章-claude-code-的模式体系" aria-label="Permalink to &quot;第 2 章　Claude Code 的模式体系&quot;">​</a></h1><p><img src="'+i+'" alt="Claude Code 模式体系：Ask/Plan/Agent/Debug"></p><p>在上一章中，我们提到 Claude Code 不是一个简单的聊天机器人，而是一个多面手的工程代理。为了适应不同的工作场景——有时你需要它大胆修改代码，有时你只需要它静静地解释逻辑——Claude Code 设计了一套清晰的<strong>模式（Modes）体系</strong>。</p><p>本章将深入剖析这四种核心模式：<strong>Ask（问询）</strong>、<strong>Plan（规划）</strong>、<strong>Agent（执行）</strong> 和 <strong>Debug（调试）</strong>。掌握它们，你就能在“思考”与“行动”之间自由切换，既保证工程安全，又最大化开发效率。</p><h2 id="_2-1-模式总览-什么时候用什么" tabindex="-1">2.1 模式总览：什么时候用什么？ <a class="header-anchor" href="#_2-1-模式总览-什么时候用什么" aria-label="Permalink to &quot;2.1 模式总览：什么时候用什么？&quot;">​</a></h2><p>在开始具体介绍之前，我们先看一张决策表，帮助你快速建立直觉：</p><table tabindex="0"><thead><tr><th style="text-align:left;">模式</th><th style="text-align:left;">核心动作</th><th style="text-align:left;">是否修改代码</th><th style="text-align:left;">典型场景</th><th style="text-align:left;">对应命令/指令</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Ask</strong></td><td style="text-align:left;"><strong>只读分析</strong></td><td style="text-align:left;">❌ 否</td><td style="text-align:left;">阅读代码、解释逻辑、回答架构问题、生成文档</td><td style="text-align:left;"><code>claude ask &quot;...&quot;</code> 或在对话中要求“只解释”</td></tr><tr><td style="text-align:left;"><strong>Plan</strong></td><td style="text-align:left;"><strong>思考与规划</strong></td><td style="text-align:left;">❌ 否 (只输出计划)</td><td style="text-align:left;">复杂重构前、需求不明确时、需要评估风险时</td><td style="text-align:left;"><code>claude plan &quot;...&quot;</code></td></tr><tr><td style="text-align:left;"><strong>Agent</strong></td><td style="text-align:left;"><strong>读写执行</strong></td><td style="text-align:left;">✅ 是</td><td style="text-align:left;">实现功能、修改 Bug、重构代码、运行测试</td><td style="text-align:left;">直接输入指令，或 <code>claude &quot;...&quot;</code> (默认)</td></tr><tr><td style="text-align:left;"><strong>Debug</strong></td><td style="text-align:left;"><strong>诊断与修复</strong></td><td style="text-align:left;">✅ 是 (修复阶段)</td><td style="text-align:left;">测试失败、报错排查、环境配置问题</td><td style="text-align:left;"><code>claude debug</code> 或传入错误日志</td></tr></tbody></table><p>你可以把这四种模式想象成一个工程师的四种“精神状态”：</p><ul><li><strong>Ask</strong> 是他在<strong>阅读文档</strong>；</li><li><strong>Plan</strong> 是他在<strong>白板前设计方案</strong>；</li><li><strong>Agent</strong> 是他在<strong>IDE 里疯狂敲代码</strong>；</li><li><strong>Debug</strong> 是他在<strong>盯着日志抓头发</strong>。</li></ul><hr><h2 id="_2-2-ask-模式-安全的-阅读与解说" tabindex="-1">2.2 Ask 模式：安全的“阅读与解说” <a class="header-anchor" href="#_2-2-ask-模式-安全的-阅读与解说" aria-label="Permalink to &quot;2.2 Ask 模式：安全的“阅读与解说”&quot;">​</a></h2><p>Ask 模式是 Claude Code 最“安全”的模式。在这个模式下，Claude Code 就像一个拥有只读权限的高级顾问。</p><h3 id="_2-2-1-核心能力" tabindex="-1">2.2.1 核心能力 <a class="header-anchor" href="#_2-2-1-核心能力" aria-label="Permalink to &quot;2.2.1 核心能力&quot;">​</a></h3><ul><li><strong>全库搜索与理解</strong>：它可以遍历整个代码库，理解文件结构和依赖关系。</li><li><strong>解释复杂逻辑</strong>：针对晦涩的算法或遗留代码，生成人类可读的解释。</li><li><strong>文档生成</strong>：根据代码自动生成 README、接口文档或注释。</li></ul><h3 id="_2-2-2-典型使用场景" tabindex="-1">2.2.2 典型使用场景 <a class="header-anchor" href="#_2-2-2-典型使用场景" aria-label="Permalink to &quot;2.2.2 典型使用场景&quot;">​</a></h3><p><strong>场景一：接手陌生项目</strong> 当你刚克隆一个新的仓库，不知道从何下手时：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;请解释这个项目的核心架构，以及主要模块之间的依赖关系&quot;</span></span></code></pre></div><p>Claude 会扫描文件结构，通过 <code>package.json</code>、<code>requirements.txt</code> 或目录命名推断架构，并给出阅读建议。</p><p><strong>场景二：理解晦涩代码</strong> 遇到一段写满“魔法数字”的函数：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;分析 src/utils/calc.ts 中的 calculateTax 函数，解释它的计算逻辑&quot;</span></span></code></pre></div><p><strong>场景三：询问工程规范</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;当前项目中是如何处理日志记录的？有没有统一的 Logger 封装？&quot;</span></span></code></pre></div><h3 id="_2-2-3-最佳实践" tabindex="-1">2.2.3 最佳实践 <a class="header-anchor" href="#_2-2-3-最佳实践" aria-label="Permalink to &quot;2.2.3 最佳实践&quot;">​</a></h3><ul><li><strong>多问“为什么”</strong>：不仅问代码“是什么”，还要问“为什么要这样写”，Claude 往往能通过上下文推断出设计意图。</li><li><strong>指定输出格式</strong>：可以明确要求它输出 Mermaid 流程图、列表或 Markdown 表格，便于你复制到文档中。</li></ul><hr><h2 id="_2-3-plan-模式-先问清-再动手" tabindex="-1">2.3 Plan 模式：先问清，再动手 <a class="header-anchor" href="#_2-3-plan-模式-先问清-再动手" aria-label="Permalink to &quot;2.3 Plan 模式：先问清，再动手&quot;">​</a></h2><p>很多开发者（以及 AI）容易犯的一个错误是：<strong>拿到需求就急着改代码，结果改错地方或引入新 Bug</strong>。Plan 模式就是为了解决这个问题而生的。</p><h3 id="_2-3-1-核心流程" tabindex="-1">2.3.1 核心流程 <a class="header-anchor" href="#_2-3-1-核心流程" aria-label="Permalink to &quot;2.3.1 核心流程&quot;">​</a></h3><p>Plan 模式不会直接执行修改，而是会输出一份<strong>结构化的实施计划</strong>。通常包含：</p><ol><li><strong>目标确认</strong>：它理解的需求是什么。</li><li><strong>现状分析</strong>：当前代码是怎样的，哪些文件会被触及。</li><li><strong>方案选项</strong>：通常提供 A/B 两种方案（例如“激进重构”vs“保守修补”）。</li><li><strong>风险评估</strong>：可能会破坏哪些现有功能。</li><li><strong>分步计划</strong>：具体的执行步骤（Step 1, Step 2...）。</li></ol><h3 id="_2-3-2-典型使用场景" tabindex="-1">2.3.2 典型使用场景 <a class="header-anchor" href="#_2-3-2-典型使用场景" aria-label="Permalink to &quot;2.3.2 典型使用场景&quot;">​</a></h3><p><strong>场景一：大型重构</strong> 你想把一个巨型组件拆分成小的子组件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;将 UserProfile.vue 拆分为 Header, BasicInfo, 和 Settings 三个子组件&quot;</span></span></code></pre></div><p>Claude 会列出拆分步骤，提醒你注意共享状态（Props/Events）的传递，并让你确认拆分边界。</p><p><strong>场景二：引入新依赖</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;引入 TanStack Query 替换现有的 axios 手动请求&quot;</span></span></code></pre></div><p>它会评估工作量，提醒你需要修改多少个文件，以及如何处理错误处理逻辑的迁移。</p><h3 id="_2-3-3-为什么即使是小任务也推荐用-plan" tabindex="-1">2.3.3 为什么即使是小任务也推荐用 Plan？ <a class="header-anchor" href="#_2-3-3-为什么即使是小任务也推荐用-plan" aria-label="Permalink to &quot;2.3.3 为什么即使是小任务也推荐用 Plan？&quot;">​</a></h3><p>即便是“修改一个字段名”这样的小任务，使用 Plan 模式也能让你<strong>二次确认</strong>影响范围。很多时候，Claude 在 Plan 阶段会发现：“哎，这个字段在数据库 Schema 里也用到了，需要同步修改迁移脚本。”——这种洞察能帮你省下几个小时的排错时间。</p><hr><h2 id="_2-4-agent-模式-真正干活的工作马" tabindex="-1">2.4 Agent 模式：真正干活的工作马 <a class="header-anchor" href="#_2-4-agent-模式-真正干活的工作马" aria-label="Permalink to &quot;2.4 Agent 模式：真正干活的工作马&quot;">​</a></h2><p>这是 Claude Code 的默认模式，也是它最强大的形态。Agent 模式结合了“思考”与“行动”，是一个完整的自主循环。</p><h3 id="_2-4-1-工作循环-the-loop" tabindex="-1">2.4.1 工作循环 (The Loop) <a class="header-anchor" href="#_2-4-1-工作循环-the-loop" aria-label="Permalink to &quot;2.4.1 工作循环 (The Loop)&quot;">​</a></h3><p>当你给出一个指令（如“实现登录页面”）时，Agent 模式会进入以下循环：</p><ol><li><strong>Search &amp; Read</strong>：搜索相关文件，读取上下文。</li><li><strong>Think</strong>：思考修改方案（在内部进行微型 Plan）。</li><li><strong>Act</strong>：调用工具进行文件编辑、创建或删除。</li><li><strong>Verify</strong>：(如果配置了) 运行 linter 或测试命令。</li><li><strong>Iterate</strong>：如果遇到错误，自动根据错误信息调整代码，直到成功或达到重试上限。</li></ol><h3 id="_2-4-2-权限与安全" tabindex="-1">2.4.2 权限与安全 <a class="header-anchor" href="#_2-4-2-权限与安全" aria-label="Permalink to &quot;2.4.2 权限与安全&quot;">​</a></h3><p>虽然 Agent 模式很强大，但它绝不是“脱缰野马”。Claude Code 内置了严格的<strong>人机确认机制</strong>（Human-in-the-loop）：</p><ul><li><strong>敏感操作需批准</strong>：删除文件、大规模修改、执行 shell 命令（特别是涉及网络或系统配置的命令）通常需要你按 <code>y</code> 确认。</li><li><strong>Diff 预览</strong>：在写入文件前，它会展示 diff 供你审查。</li></ul><h3 id="_2-4-3-典型使用场景" tabindex="-1">2.4.3 典型使用场景 <a class="header-anchor" href="#_2-4-3-典型使用场景" aria-label="Permalink to &quot;2.4.3 典型使用场景&quot;">​</a></h3><ul><li><strong>功能开发</strong>：“创建一个新的 API 接口 <code>/api/v1/users</code>，支持分页查询。”</li><li><strong>测试补充</strong>：“为 <code>src/utils</code> 目录下的所有工具函数补充单元测试，覆盖率要求 80% 以上。”</li><li><strong>批量修改</strong>：“把所有用到 <code>var</code> 的地方改为 <code>const</code> 或 <code>let</code>。”</li></ul><hr><h2 id="_2-5-debug-repair-模式-围绕错误的快速响应" tabindex="-1">2.5 Debug / Repair 模式：围绕错误的快速响应 <a class="header-anchor" href="#_2-5-debug-repair-模式-围绕错误的快速响应" aria-label="Permalink to &quot;2.5 Debug / Repair 模式：围绕错误的快速响应&quot;">​</a></h2><p>开发中最令人头秃的时刻莫过于：测试红了一片，或者控制台疯狂报错。Debug 模式（有时也称为 Repair 模式或工作流）是专门为此设计的急救包。</p><h3 id="_2-5-1-核心能力" tabindex="-1">2.5.1 核心能力 <a class="header-anchor" href="#_2-5-1-核心能力" aria-label="Permalink to &quot;2.5.1 核心能力&quot;">​</a></h3><ul><li><strong>日志分析</strong>：它可以直接读取终端输出的错误堆栈，解析文件路径和行号。</li><li><strong>测试驱动修复</strong>：它可以反复运行失败的测试命令，每次修改后自动验证，直到测试通过。</li><li><strong>根因定位</strong>：它不仅修复表面错误，还会尝试查找导致错误的根本原因（例如配置错误、依赖冲突）。</li></ul><h3 id="_2-5-2-典型使用场景" tabindex="-1">2.5.2 典型使用场景 <a class="header-anchor" href="#_2-5-2-典型使用场景" aria-label="Permalink to &quot;2.5.2 典型使用场景&quot;">​</a></h3><p><strong>场景一：测试挂了</strong> 你刚跑完 <code>npm test</code>，发现有 3 个测试失败。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> debug</span></span></code></pre></div><p>或者直接把错误日志粘贴给它。Claude 会分析失败原因，定位到具体代码行，并提出修复补丁。</p><p><strong>场景二：启动报错</strong> 项目启动不起来，报错 <code>Module not found</code>。 Claude Code 可以检查 <code>node_modules</code>、<code>package.json</code> 和文件路径，帮你找出是没安装依赖，还是导入路径写错了。</p><h3 id="_2-5-3-最佳实践-提供尽可能多的上下文" tabindex="-1">2.5.3 最佳实践：提供尽可能多的上下文 <a class="header-anchor" href="#_2-5-3-最佳实践-提供尽可能多的上下文" aria-label="Permalink to &quot;2.5.3 最佳实践：提供尽可能多的上下文&quot;">​</a></h3><p>在 Debug 模式下，信息的完整性至关重要。</p><ul><li>如果是运行时错误，尽量提供完整的堆栈跟踪。</li><li>如果是逻辑错误，描述清楚“预期的行为”和“实际的行为”。</li><li>告诉 Claude 你最近修改了什么（或者让它自己看 <code>git diff</code>），因为 Bug 往往就藏在最近的变动里。</li></ul><hr><h2 id="_2-6-小结" tabindex="-1">2.6 小结 <a class="header-anchor" href="#_2-6-小结" aria-label="Permalink to &quot;2.6 小结&quot;">​</a></h2><ul><li><strong>Ask</strong> 用于<strong>懂</strong>：阅读、解释、文档。</li><li><strong>Plan</strong> 用于<strong>想</strong>：架构、重构、风险评估。</li><li><strong>Agent</strong> 用于<strong>做</strong>：编码、测试、重构。</li><li><strong>Debug</strong> 用于<strong>修</strong>：排错、修复测试。</li></ul><p>熟练的 Claude Code 用户，往往会像这样组合使用：</p><blockquote><p>“先用 <strong>Ask</strong> 搞懂现有逻辑，再用 <strong>Plan</strong> 制定重构方案，确认无误后让 <strong>Agent</strong> 执行修改，最后如果遇到边缘情况报错，用 <strong>Debug</strong> 快速收尾。”</p></blockquote><p>下一章，我们将把这些模式串联起来，看看在真实的日常工作流中，它们是如何协同工作的。</p>',69)])])}const k=a(n,[["render",o]]);export{u as __pageData,k as default};
